import lxml.etree as ET
from io import StringIO

def process_soap_request(xml_string):
    try:
        # Parse the XML string into an ElementTree object
        xml_tree = ET.parse(StringIO(xml_string))

        # Get the root element of the SOAP envelope
        soap_envelope = xml_tree.getroot()

        # Check if the DTD is valid
        dtd_valid = validate_dtd(soap_envelope)

        if not dtd_valid:
            return "DTD validation failed"

        # Extract the message body from the SOAP envelope
        message_body = soap_envelope.find('{http://schemas.xmlsoap.org/soap/envelope/}Body')

        if message_body is None:
            return "Message body not found in SOAP envelope"

        # Return the extracted message body as a string
        return ET.tostring(message_body, encoding='unicode')

    except ET.XMLSyntaxError as e:
        return f"XML syntax error: {e}"

def validate_dtd(root):
    dtd = root.docinfo.dtd
    if dtd is None or not dtd.system_url.startswith('DTD'):
        return True  # No DTD specified, so it's valid

    try:
        ET.parse(dtd.system_url)
        return True
    except ET.XMLSyntaxError as e:
        return False